const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export function quote(customer: { yearsWithMHPCO: number }, items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>, isFollowUpContract: boolean): number {
  if (items.length === 0) return 5;

  let totalItemPremium = 0;
  for (const item of items) {
    totalItemPremium += BASE_PREMIUMS[item.type] ?? 0;
  }

  let policyPremium = totalItemPremium;
  policyPremium += totalItemPremium * 0.1; // first insurance

  const total = policyPremium + 5;
  return Math.ceil(total);
}

