const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_PREMIUM = 60;

function computeBasePremium(items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += BASE_PREMIUMS[item.type] ?? 0;
    }
  }

  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * (BASE_PREMIUMS[type] ?? 0);
    }
  }

  return total;
}

export function quote(customer: { yearsWithMHPCO: number }, items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>, isFollowUpContract: boolean): number {
  if (items.length === 0) return 5;

  const basePremium = computeBasePremium(items);
  const firstInsurance = basePremium * 0.1;

  return Math.ceil(basePremium + firstInsurance + 5);
}

