  moonstone: 25,
};

export function quote(customer: { yearsWithMHPCO: number }, items: Array<{ type: string; material?: string; enchantment?: number; cursed?: boolean }>, isFollowUpContract: boolean): number {
  if (items.length === 0) return 5;

  const basePremium = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
